1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type ScenarioResult = { results: QuoteResult[] };
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_SURCHARGE = 0.1;
21	
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	};
26	
27	const itemPremium = (item: Item): number => {
28	  const base = BASE_PREMIUMS[item.type] ?? 0;
29	  return base + base * FIRST_INSURANCE_SURCHARGE;
30	};
31	
32	const quoteStep = (step: QuoteStep): QuoteResult => {
33	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
34	  return { premium: itemsTotal + PROCESSING_FEE };
35	};
36	
37	export const runScenario = (scenario: Scenario): ScenarioResult => {
38	  return { results: scenario.steps.map(quoteStep) };
39	};
